INSERT INTO public.question_bank_questions
(product_slug, bank_type, category, question, options, correct_answer, explanation, sort_order)
VALUES
('healthshield-gold-max','exam','suitability','Which client is least suitable for Plan A?','["High-income professional wanting private hospital access","Business owner with strong cash flow","Cost-sensitive client with limited savings","Dual-income household"]'::jsonb, 2, 'Plan A has higher premiums. Suitability depends on long-term affordability, not just preference.', 36),
('healthshield-gold-max','exam','suitability','A client wants the "best plan" but is unsure about future affordability. What should you do?','["Recommend Plan A anyway","Recommend a sustainable plan aligned with long-term affordability","Push for highest coverage","Ignore concern"]'::jsonb, 1, 'Sustainability is more important than maximum coverage.', 37),
('healthshield-gold-max','exam','suitability','A client has no emergency savings but wants full rider coverage. Best approach?','["Proceed","Recommend balancing insurance with emergency fund","Ignore","Sell rider only"]'::jsonb, 1, 'Insurance complements — not replaces — liquidity planning.', 38),
('healthshield-gold-max','exam','suitability','When should Plan B be preferred over Plan A?','["When client wants maximum coverage","When affordability is a concern","When client is young","When MediSave is used"]'::jsonb, 1, 'Plan B offers a balance between cost and coverage.', 39),
('healthshield-gold-max','exam','compliance','Which statement is NOT compliant?','["Coverage depends on policy terms","You may still have out-of-pocket costs","This plan guarantees full coverage of all hospital bills","We should assess your needs first"]'::jsonb, 2, 'Full coverage cannot be guaranteed.', 40),
('healthshield-gold-max','exam','compliance','A client asks if rider removes all costs. Best response?','["Yes","No, some cost-sharing remains including deductible","Yes if claim is large","Only first claim"]'::jsonb, 1, 'Under new rules, deductible cannot be covered.', 41),
('healthshield-gold-max','exam','compliance','What must you avoid saying?','["You may still pay part of the bill","This helps reduce large costs","You will never pay anything out of pocket","Claims depend on conditions"]'::jsonb, 2, 'Absolute guarantees are misleading and non-compliant.', 42),
('healthshield-gold-max','exam','advisory-skills','A client compares based only on premium. What should you do?','["Compete on price","Reframe to value, coverage, and risk","Criticize competitors","Avoid discussion"]'::jsonb, 1, 'Shift focus from price to long-term value and coverage.', 43),
('healthshield-gold-max','exam','advisory-skills','Best first question before recommending plan?','["What plan do you want?","What are your healthcare concerns?","What is your budget?","Do you want rider?"]'::jsonb, 1, 'Discovery questions about concerns open meaningful planning conversations.', 44),
('healthshield-gold-max','exam','advisory-skills','What differentiates strong advisor?','["Product knowledge only","Matching solutions to client needs","Fast closing","Selling highest premium"]'::jsonb, 1, 'True advisory is about alignment with client needs.', 45),
('healthshield-gold-max','exam','advisory-skills','Client says "I''ll rely on MediShield Life." What do you do?','["Agree","Explain limitations and gaps","Push","Ignore"]'::jsonb, 1, 'MediShield Life provides basic coverage but leaves gaps, especially for private care.', 46),
('healthshield-gold-max','exam','closing','Client says "I need to think." Best response?','["Wait","Clarify concerns + follow-up","Push","End"]'::jsonb, 1, 'Effective closing identifies and resolves hesitation rather than waiting passively.', 47),
('healthshield-gold-max','exam','closing','Client says "Premium too high." Best move?','["Push","Adjust plan structure","Ignore","End"]'::jsonb, 1, 'Objection often reflects affordability mismatch — adjust solution instead of forcing.', 48),
('healthshield-gold-max','exam','closing','Client needs spouse input. Best move?','["Push","Arrange joint meeting","Ignore","Close anyway"]'::jsonb, 1, 'Involving decision-makers improves clarity and conversion.', 49),
('healthshield-gold-max','exam','closing','Client unsure. Best action?','["Pressure","Reconfirm needs + fit","Ignore","Delay"]'::jsonb, 1, 'Uncertainty often comes from unclear fit — revisit fundamentals.', 50),
('healthshield-gold-max','exam','roleplay','Client says: "I can pay cash." Best response?','["Agree","Highlight unpredictability of large bills","Push","Ignore"]'::jsonb, 1, 'Self-insurance may not be realistic for large medical bills.', 51),
('healthshield-gold-max','exam','roleplay','Client says: "Insurance companies don''t pay." Best response?','["Promise claims","Explain claims conditions and process","Avoid","Ignore"]'::jsonb, 1, 'Transparency builds trust. Educate without overpromising.', 52),
('healthshield-gold-max','exam','roleplay','Client confused by complexity. Best approach?','["Skip","Simplify with examples","Push","Delay"]'::jsonb, 1, 'Simplification with concrete examples improves understanding.', 53),
('healthshield-gold-max','exam','roleplay','Client comparing insurers. Best move?','["Attack competitors","Provide structured comparison","Avoid","Push"]'::jsonb, 1, 'Structured, fair comparisons build trust and credibility.', 54),
('healthshield-gold-max','exam','suitability','Client has unstable income. What do you do?','["Sell Plan A","Recommend affordable option","Ignore","Push"]'::jsonb, 1, 'Income volatility requires sustainable, affordable solutions.', 55),
('healthshield-gold-max','exam','suitability','Client nearing retirement. Key concern?','["Premium stability","Budget","Coverage","All"]'::jsonb, 3, 'Pre-retirees must consider all factors: premium stability, budget, and coverage adequacy.', 56),
('healthshield-gold-max','exam','advisory-skills','Advisor''s main role?','["Sell product","Solve client problem","Close fast","Max premium"]'::jsonb, 1, 'Advisors are problem-solvers, not just product sellers.', 57),
('healthshield-gold-max','exam','advisory-skills','What shows overselling?','["Explaining product","Recommending before understanding client","Asking questions","Comparing options"]'::jsonb, 1, 'Recommending without discovery is a hallmark of overselling.', 58),
('healthshield-gold-max','exam','closing','Ultimate goal?','["Close deal","Build trust and long-term relationship","Max premium","Hit target"]'::jsonb, 1, 'Long-term trust drives retention, referrals, and sustained success.', 59);